{"code": "import json

# Get the file path
packages_path = locals()['var_functions.query_db:26']

# Load packages
with open(packages_path, 'r') as f:
    all_packages = json.load(f)

print('Loaded', len(all_packages), 'packages')

# Process packages
latest_pkgs = {}
for pkg in all_packages:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease', False):
            name = pkg['Name']
            ts = float(pkg['UpstreamPublishedAt'])
            if name not in latest_pkgs or ts > latest_pkgs[name]['ts']:
                latest_pkgs[name] = {
                    'name': name,
                    'version': pkg['Version'],
                    'ts': ts
                }
    except:
        pass

result = json.dumps({'count': len(latest_pkgs), 'sample': list(latest_pkgs.values())[:3]})
print('__RESULT__:')
print(result)"}

