from collections import defaultdict

# Load complete latest packages (file-based)
all_npm_packages_file = var_functions.query_db:26
with open(all_npm_packages_file, 'r') as f:
    all_packages = json.load(f)

print('Total packages loaded:', len(all_packages))

# Find latest release version for each package
latest_pkgs = {}
for pkg in all_packages:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        if version_info.get('IsRelease', False):
            name = pkg['Name']
            ts = float(pkg['UpstreamPublishedAt'])
            if name not in latest_pkgs or ts > latest_pkgs[name]['ts']:
                latest_pkgs[name] = {
                    'name': name,
                    'version': pkg['Version'],
                    'ts': ts
                }
    except:
        pass

print('Latest release packages:', len(latest_pkgs))

# Load all project_packageversion records
ppv_file = var_functions.query_db:32
with open(ppv_file, 'r') as f:
    ppv_records = json.load(f)

print('PPV records:', len(ppv_records))

# Build lookup map: (name, version) -> project_name
ppv_map = {}
for record in ppv_records:
    key = (record['Name'], record['Version'])
    if key not in ppv_map:  # Avoid duplicates
        ppv_map[key] = record['ProjectName']

print('Lookup map size:', len(ppv_map))

# Match packages with projects
matched = []
for pkg_key, pkg_info in latest_pkgs.items():
    key = (pkg_info['name'], pkg_info['version'])
    if key in ppv_map:
        matched.append({
            'name': pkg_info['name'],
            'version': pkg_info['version'],
            'project': ppv_map[key],
            'ts': pkg_info['ts']
        })

print('Matched packages:', len(matched))

# Save matched data for next step
output = {'matched_packages': matched}
print('__RESULT__:')
print(json.dumps(output))"}

